def _solve(n, edges):
    m = len(edges)
    idx_edges = sorted(range(m), key=lambda i: edges[i][2])

    def kruskal(skip=-1, force=-1):
        parent = list(range(n))

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(a, b):
            ra, rb = find(a), find(b)
            if ra == rb:
                return False
            parent[ra] = rb
            return True

        weight = 0
        count = 0
        if force != -1:
            a, b, w = edges[force]
            if union(a, b):
                weight += w
                count += 1
        for i in idx_edges:
            if i == skip or i == force:
                continue
            a, b, w = edges[i]
            if union(a, b):
                weight += w
                count += 1
        if count != n - 1:
            return float('inf')
        return weight

    baseline = kruskal()
    critical = []
    pseudo = []
    for i in range(m):
        if kruskal(skip=i) > baseline:
            critical.append(i)
        elif kruskal(force=i) == baseline:
            pseudo.append(i)
    return [critical, pseudo]


def validate(args, output):
    n, edges = args
    if not isinstance(output, list) or len(output) != 2:
        return False
    crit_out, pseudo_out = output
    if not isinstance(crit_out, list) or not isinstance(pseudo_out, list):
        return False
    if len(crit_out) != len(set(crit_out)) or len(pseudo_out) != len(set(pseudo_out)):
        return False
    if set(crit_out) & set(pseudo_out):
        return False
    correct = _solve(n, edges)
    return set(crit_out) == set(correct[0]) and set(pseudo_out) == set(correct[1])

