function _solve(n, edges) {
    const m = edges.length;
    const idxEdges = Array.from({ length: m }, (_, i) => i).sort((a, b) => edges[a][2] - edges[b][2]);
    function kruskal(skip, force) {
        const parent = Array.from({ length: n }, (_, i) => i);
        function find(x) {
            while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; }
            return x;
        }
        function union(a, b) {
            const ra = find(a), rb = find(b);
            if (ra === rb) return false;
            parent[ra] = rb;
            return true;
        }
        let weight = 0, count = 0;
        if (force !== -1) {
            const [a, b, w] = edges[force];
            if (union(a, b)) { weight += w; count += 1; }
        }
        for (const i of idxEdges) {
            if (i === skip || i === force) continue;
            const [a, b, w] = edges[i];
            if (union(a, b)) { weight += w; count += 1; }
        }
        if (count !== n - 1) return Infinity;
        return weight;
    }
    const baseline = kruskal(-1, -1);
    const critical = [], pseudo = [];
    for (let i = 0; i < m; i++) {
        if (kruskal(i, -1) > baseline) {
            critical.push(i);
        } else if (kruskal(-1, i) === baseline) {
            pseudo.push(i);
        }
    }
    return [critical, pseudo];
}

function validate(args, output) {
    const [n, edges] = args;
    if (!Array.isArray(output) || output.length !== 2) return false;
    const [critOut, pseudoOut] = output;
    if (!Array.isArray(critOut) || !Array.isArray(pseudoOut)) return false;
    if (new Set(critOut).size !== critOut.length) return false;
    if (new Set(pseudoOut).size !== pseudoOut.length) return false;
    const critSet = new Set(critOut);
    for (const p of pseudoOut) if (critSet.has(p)) return false;
    const correct = _solve(n, edges);
    const a = new Set(critOut), b = new Set(correct[0]);
    if (a.size !== b.size) return false;
    for (const x of a) if (!b.has(x)) return false;
    const c = new Set(pseudoOut), d = new Set(correct[1]);
    if (c.size !== d.size) return false;
    for (const x of c) if (!d.has(x)) return false;
    return true;
}

