import itertools


class Solution:
    def findCriticalAndPseudoCriticalEdges(self, n, edges):
        m = len(edges)

        def is_spanning_tree(idxs):
            parent = list(range(n))

            def find(x):
                while parent[x] != x:
                    parent[x] = parent[parent[x]]
                    x = parent[x]
                return x

            for i in idxs:
                a, b, _ = edges[i]
                ra, rb = find(a), find(b)
                if ra == rb:
                    return False
                parent[ra] = rb
            return len({find(x) for x in range(n)}) == 1

        best = None
        best_sets = []
        for combo in itertools.combinations(range(m), n - 1):
            if is_spanning_tree(combo):
                w = sum(edges[i][2] for i in combo)
                if best is None or w < best:
                    best = w
                    best_sets = [set(combo)]
                elif w == best:
                    best_sets.append(set(combo))
        critical = set.intersection(*best_sets)
        pseudo = set.union(*best_sets) - critical
        return [sorted(critical), sorted(pseudo)]

